mapper.select:
select id, user_id, favorite_type, target_id, title, description, create_time
from user_favorite
where user_id = #{userId}
  and favorite_type = #{favoriteType}
  and target_id = #{targetId}
limit 1

mapper.delete:
delete from user_favorite
where user_id = #{userId}
  and favorite_type = #{favoriteType}
  and target_id = #{targetId}
